/// Cross-axis alignment options for Wrap widget runs.
///
/// Determines how runs (lines) of wrapped children are aligned along
/// the cross axis of the wrap layout.
enum StacWrapCrossAlignment {
  /// Align runs to the start of the cross axis.
  start,

  /// Align runs to the end of the cross axis.
  end,

  /// Center runs along the cross axis.
  center,
}
